linkList.script:
var page = this.KMComponentsMng && this.KMComponentsMng.get ? this.KMComponentsMng.get("PageView") : null;
var btn = this;
function setBtnText(t) {
  try { if (btn.button) btn.button({ text: t }); } catch(e) {}
  try { btn.propData = btn.propData || {}; btn.propData.detailConfig = "this.button({ text: " + JSON.stringify(t) + " })"; } catch(e) {}
}
function saveSmoke(obj) {
  try { if (page) page.__palBackendSmoke = obj; } catch(e) {}
  try { window.__palBackendSmoke = obj; } catch(e) {}
}
setBtnText("Smoke calling...");
(function(){
  function changeSpace() {
    if (typeof SetRunInfo !== "function") return Promise.resolve({ret:"NO_SetRunInfo"});
    return new Promise(function(resolve) {
      try {
        SetRunInfo({ stType: 5, spaceTime: "PalimpsestL1_0626R2", devName: "PalimpsestBack_0626R2" }, function(res) { resolve(res); });
      } catch(e) { resolve({ret:"SetRunInfoError", message:String(e)}); }
    });
  }
  function doCallByName() {
    var param = new StringMap({ type: 21001, cloudID: getLocalCloudID(), areaID: 0, timeout: 8000 });
    var input = new StringMap({
      identifierType: 2,
      name: "PalimpsestBackend_CUSTOMFUNC_CUSTOMFUNC@PalimpsestBack_0626R2",
      funcname: "QueryAssessmentSmoke",
      params: []
    });
    return Call(param, input);
  }
  function doCallById() {
    var param = new StringMap({ type: 21001, cloudID: getLocalCloudID(), areaID: 0, timeout: 8000 });
    var input = new StringMap({
      identifierType: 1,
      id: "7205759403792797099",
      funcname: "QueryAssessmentSmoke",
      params: []
    });
    return Call(param, input);
  }
  changeSpace().then(function(stRes) {
    return doCallByName().then(function(callRes) {
      if (callRes && callRes.ret === 0) return {setRunInfo:stRes, mode:"name", call:callRes};
      return doCallById().then(function(callRes2) { return {setRunInfo:stRes, mode:"id", firstCall:callRes, call:callRes2}; });
    });
  }).then(function(res) {
    var ret = res && res.call ? res.call.ret : undefined;
    saveSmoke({ok:ret===0, ret:ret, result:res, at:Date.now()});
    setBtnText(ret === 0 ? "Smoke OK" : ("Smoke ret=" + ret));
  }).catch(function(err) {
    saveSmoke({ok:false, error:String(err), at:Date.now()});
    setBtnText("Smoke error");
  });
})();

